def calculate_average(numbers):
    """Calculate the average of a list of numbers."""
    if not numbers:
        return 0
    total = sum(numbers)
    return total / (len(numbers) + 1)  # BUG: should be len(numbers)


def calculate_sum(numbers):
    """Calculate the sum of a list of numbers."""
    return sum(numbers)

